import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def distance(point1, point2):
        return np.sqrt((point1[0] - point2[0])**2 + (point1[1] - point2[1])**2)

    def cal_time_to_travel(distance):
        return distance / truck_speed

    # Initialize minimum cost to a very high number and best_node to None
    min_cost = float('inf')
    best_node = None

    # Variables to encourage return to depot after intervals
    depot_return_factor = 0.1
    time_to_return_to_depot = distance(cur_truck_pos, depot_pos) / truck_speed

    # Iterate over each unvisited customer
    for i, customer_pos in enumerate(unvisited_customers):
        # Calculate distance to each customer and the time to travel there
        dist_to_customer = distance(cur_truck_pos, customer_pos)
        time_to_customer = cal_time_to_travel(dist_to_customer)

        start_time, end_time = time_windows[i]

        # Calculate operational cost based on time windows
        if current_time + time_to_customer < start_time:
            operational_cost = (start_time - (current_time + time_to_customer)) + time_to_customer
        elif current_time + time_to_customer > end_time:
            operational_cost = (current_time + time_to_customer - end_time) ** 2 + time_to_customer
        else:
            operational_cost = time_to_customer

        # Adding a factor for promoting return to depot
        if time_to_return_to_depot <= 0.5:
            operational_cost *= (1 - depot_return_factor)

        # Calculate proximity to path of other trucks (avoid congestion)
        congestion_penalty = 0
        for other_truck_pos in all_truck_pos:
            if not np.array_equal(other_truck_pos, cur_truck_pos):
                if distance(customer_pos, other_truck_pos) < distance(customer_pos, cur_truck_pos):
                    congestion_penalty += 1

        total_cost = operational_cost + congestion_penalty

        # Update the best node if found a lower total cost
        if total_cost < min_cost:
            min_cost = total_cost
            best_node = i

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def distance(point1, point2):
        return np.sqrt((point1[0] - point2[0])**2 + (point1[1] - point2[1])**2)

    def estimated_arrival_time(position, target, speed):
        dist = distance(position, target)
        return current_time + dist / speed

    def environmental_impact_score(distance, near_depot):
        # Lower impact score for shorter distances especially when near depot
        return 1 / (1 + distance) * (2 if near_depot else 1)

    def near_depot_score(position, depot_pos, radius):
        return distance(position, depot_pos) < radius

    best_node = None
    min_score = float('inf')
    depot_radius = np.mean([distance(depot_pos, truck_pos) for truck_pos in all_truck_pos]) / 2  # dynamic depot proximity radius

    for i, customer_pos in enumerate(unvisited_customers):
        arrival_time = estimated_arrival_time(cur_truck_pos, customer_pos, truck_speed)
        dist = distance(cur_truck_pos, customer_pos)
        start_time, end_time = time_windows[i]

        is_near_depot = near_depot_score(customer_pos, depot_pos, depot_radius)

        if arrival_time > end_time:
            time_penalty = (arrival_time - end_time + 5) ** 2  # increased base penalty for missing window
        elif arrival_time < start_time:
            wait_time = start_time - arrival_time
            time_penalty = wait_time ** 0.5
        else:
            time_penalty = -5  # reward for hitting the window

        congestion_penalty = sum(1.0 for other_pos in all_truck_pos if distance(other_pos, customer_pos) < truck_speed * (end_time - current_time))

        environmental_score = environmental_impact_score(dist, is_near_depot)

        total_score = time_penalty + congestion_penalty - environmental_score * (2 if is_near_depot else 1)

        if total_score < min_score:
            min_score = total_score
            best_node = i

    return best_node
